import { readFileSync } from 'node:fs';
import * as core from '@actions/core';
import { CreateRepositoryCommand, DescribeRepositoriesCommand, PutLifecyclePolicyCommand, SetRepositoryPolicyCommand, } from '@aws-sdk/client-ecr';
const isRepositoryNotFoundException = (e) => e instanceof Error && e.name === 'RepositoryNotFoundException';
export async function createRepositoryIfNotExist(client, name) {
    try {
        const describe = await client.send(new DescribeRepositoriesCommand({ repositoryNames: [name] }));
        const found = describe.repositories?.[0];
        core.info(`Repository ${found.repositoryUri} already exists`);
        return { repositoryUri: found.repositoryUri };
    }
    catch (error) {
        if (isRepositoryNotFoundException(error)) {
            const create = await client.send(new CreateRepositoryCommand({ repositoryName: name }));
            const repo = create.repository;
            core.info(`Repository ${repo.repositoryUri} has been created`);
            return { repositoryUri: repo.repositoryUri };
        }
        throw error;
    }
}
export async function putLifecyclePolicy(client, repositoryName, path) {
    const lifecyclePolicyText = readFileSync(path, { encoding: 'utf-8' });
    await client.send(new PutLifecyclePolicyCommand({ repositoryName, lifecyclePolicyText }));
    core.info(`Put lifecycle policy ${path} on repository ${repositoryName}`);
}
export async function setRepositoryPolicy(client, repositoryName, path) {
    const policyText = readFileSync(path, { encoding: 'utf-8' });
    await client.send(new SetRepositoryPolicyCommand({ repositoryName, policyText }));
    core.info(`Set repository policy ${path} on repository ${repositoryName}`);
}
